1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
6	<title>Ballet Intelligent Learning Portal</title>
7	<style>
8	  :root{
9	    --bg:#0e0b12; --panel:#181420; --panel2:#1f1a29; --accent:#c9a0dc;
10	    --accent2:#e8c7ff; --text:#f3eef7; --muted:#9c8fae; --green:#3ddc84; --red:#ff4d5e;
11	  }
12	  *{box-sizing:border-box;}
13	  body{
14	    margin:0; font-family:'Segoe UI',system-ui,sans-serif; background:var(--bg); color:var(--text);
15	  }
16	  header{
17	    padding:18px 28px; border-bottom:1px solid #2a2434; display:flex; justify-content:space-between; align-items:center;
18	  }
19	  header h1{font-size:1.15rem; margin:0; letter-spacing:.5px; font-weight:600;}
20	  header span{color:var(--muted); font-size:.8rem;}
21	
22	  .hero{
23	    position:relative; height:380px; overflow:hidden; display:flex; align-items:center; justify-content:center; text-align:center;
24	  }
25	  .hero video{
26	    position:absolute; inset:0; width:100%; height:100%; object-fit:cover; filter:brightness(.4) saturate(1.1);
27	  }
28	  .hero::after{
29	    content:""; position:absolute; inset:0; background:linear-gradient(180deg, rgba(14,11,18,.15), rgba(14,11,18,.95));
30	  }
31	  .hero-content{position:relative; z-index:2; padding:0 20px;}
32	  .hero-content .eyebrow{
33	    color:var(--accent2); font-size:.72rem; letter-spacing:2px; text-transform:uppercase; margin-bottom:10px; display:block;
34	  }
35	  .hero-content h1{
36	    font-size:clamp(1.8rem,5vw,3.2rem); margin:0 0 12px; font-weight:700; letter-spacing:.5px;
37	  }
38	  .hero-content p{
39	    color:#d8cbe5; font-size:.95rem; max-width:520px; margin:0 auto;
40	  }
41	  .layout{
42	    display:flex; gap:18px; padding:22px; max-width:1400px; margin:0 auto; flex-wrap:wrap; justify-content:center;
43	  }
44	  .column{
45	    background:var(--panel); border-radius:14px; padding:14px; width:380px; display:flex; flex-direction:column; gap:12px;
46	  }
47	  .tabs{display:flex; gap:6px;}
48	  .tab-btn{
49	    flex:1; background:var(--panel2); border:none; color:var(--muted); padding:10px 8px; border-radius:9px;
50	    font-size:.78rem; cursor:pointer; transition:.15s; font-weight:600; letter-spacing:.3px;
51	  }
52	  .tab-btn.active{background:var(--accent); color:#211a2b;}
53	  .tab-btn.locked{opacity:.5; cursor:not-allowed; pointer-events:none;}
54	  .tab-panel{display:none;}
55	  .tab-panel.active{display:flex; flex-direction:column; gap:10px;}
56	
57	  .rule-item{
58	    background:var(--panel2); padding:10px; border-radius:9px; display:flex; flex-direction:column; gap:8px;
59	    font-size:.82rem; line-height:1.35; cursor:pointer; border:1px solid transparent;
60	  }
61	  .rule-item.checked{border-color:var(--green);}
62	  .rule-item input{margin-top:2px;}
63	  .rule-video{
64	    width:100%; aspect-ratio:16/9; border-radius:7px; overflow:hidden; background:#000; position:relative;
65	  }
66	  .rule-video video{width:100%; height:100%; object-fit:cover; display:block;}
67	  .rule-video .clip-badge{
68	    position:absolute; bottom:6px; left:6px; background:rgba(0,0,0,.55); font-size:.62rem; padding:2px 7px; border-radius:5px; color:var(--accent2);
69	  }
70	  .rule-check-row{display:flex; gap:9px; align-items:flex-start;}
71	  .rule-title{font-weight:700; display:block; margin-bottom:2px;}
72	  .progress-note{font-size:.75rem; color:var(--muted); text-align:center;}
73	
74	  .video-frame{
75	    position:relative; width:100%; aspect-ratio:9/16; background:#000; border-radius:12px; overflow:hidden;
76	    border:4px solid #2a2434; transition:border-color .3s ease, box-shadow .3s ease;
77	  }
78	  .video-frame video, .video-frame canvas{
79	    width:100%; height:100%; object-fit:cover; position:absolute; top:0; left:0;
80	  }
81	  .video-frame.border-green{border-color:var(--green); box-shadow:0 0 22px 2px rgba(61,220,132,.55);}
82	  .video-frame.border-red{border-color:var(--red); box-shadow:0 0 22px 2px rgba(255,77,94,.55);}
83	
84	  .overlay-badge{
85	    position:absolute; top:8px; left:8px; background:rgba(0,0,0,.55); padding:4px 9px; border-radius:6px;
86	    font-size:.68rem; letter-spacing:.4px; z-index:5;
87	  }
88	  .record-trigger{
89	    position:absolute; top:8px; left:8px; z-index:6; background:rgba(255,77,94,.9); border:none; color:#fff;
90	    width:34px; height:34px; border-radius:50%; cursor:pointer; font-size:.9rem; display:flex; align-items:center; justify-content:center;
91	  }
92	  .countdown-overlay{
93	    position:absolute; inset:0; display:none; align-items:center; justify-content:center; z-index:20;
94	    background:rgba(0,0,0,.45); font-size:4rem; font-weight:700; color:var(--accent2);
95	  }
96	  .countdown-overlay.show{display:flex;}
97	
98	  .controls-row{display:flex; gap:8px;}
99	  button.primary{
100	    background:linear-gradient(135deg,var(--accent),#8f6bb0); border:none; color:#1a1420; font-weight:700;
101	    padding:11px; border-radius:9px; cursor:pointer; font-size:.82rem; flex:1;
102	  }
103	  button.primary:disabled{opacity:.4; cursor:not-allowed;}
104	  button.secondary{
105	    background:var(--panel2); border:1px solid #332b40; color:var(--text); padding:11px; border-radius:9px;
106	    cursor:pointer; font-size:.8rem; flex:1;
107	  }
108	  .scrub{width:100%;}
109	  .status-line{font-size:.75rem; color:var(--muted); min-height:16px;}
110	  .score-readout{font-size:1.4rem; font-weight:700; text-align:center;}
111	  .score-readout.green{color:var(--green);}
112	  .score-readout.red{color:var(--red);}
113	
114	  .calendar-section{
115	    max-width:1400px; margin:0 auto 40px; padding:0 22px;
116	  }
117	  .calendar-section h2{font-size:1rem; margin-bottom:14px;}
118	  .cal-nav{
119	    display:flex; align-items:center; justify-content:center; gap:16px; margin-bottom:14px;
120	  }
121	  .cal-nav button{
122	    background:var(--panel2); border:1px solid #332b40; color:var(--text); width:32px; height:32px; border-radius:8px;
123	    cursor:pointer; font-size:.9rem;
124	  }
125	  .cal-nav .cal-month-label{font-weight:700; font-size:.95rem; min-width:170px; text-align:center;}
126	  .cal-weekdays{
127	    display:grid; grid-template-columns:repeat(7,1fr); gap:6px; margin-bottom:6px;
128	  }
129	  .cal-weekdays div{text-align:center; font-size:.68rem; color:var(--muted); letter-spacing:.5px;}
130	  .cal-grid{
131	    display:grid; grid-template-columns:repeat(7,1fr); gap:6px;
132	  }
133	  .cal-cell{
134	    background:var(--panel); border-radius:8px; padding:10px 6px; text-align:center; font-size:.72rem; color:var(--muted);
135	    min-height:64px; display:flex; flex-direction:column; justify-content:center; gap:4px; border:1px solid transparent;
136	  }
137	  .cal-cell.empty{background:transparent;}
138	  .cal-cell.today{border-color:var(--accent); color:var(--text);}
139	  .cal-cell.task-green{background:rgba(61,220,132,.14); border-color:var(--green); color:var(--text);}
140	  .cal-cell.task-red{background:rgba(255,77,94,.14); border-color:var(--red); color:var(--text);}
141	  .cal-cell .dnum{font-weight:700; font-size:.85rem;}
142	  .footnote{font-size:.72rem; color:var(--muted); margin-top:10px;}
143	</style>
144	</head>
145	<body>
146	
147	<section class="hero">
148	  <video autoplay muted loop playsinline id="heroVideo">
149	    <source src="https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4" type="video/mp4">
150	  </video>
151	  <div class="hero-content">
152	    <span class="eyebrow">Placeholder title &amp; background — swap before launch</span>
153	    <h1>Find Your Center. Perfect Your Form.</h1>
154	    <p>An AI-guided ballet studio in your browser — real-time pose tracking, instant feedback, and a practice plan built around you.</p>
155	  </div>
156	</section>
157	
158	<header>
159	  <h1>🩰 Ballet Intelligent Learning Portal</h1>
160	  <span>Functional prototype — MediaPipe pose tracking · placeholder reference footage</span>
161	</header>
162	
163	<div class="layout">
164	
165	  <!-- LEFT PANEL -->
166	  <div class="column" id="leftPanel">
167	    <div class="tabs">
168	      <button class="tab-btn active" id="leftTab1Btn" onclick="switchLeftTab(1)">1 · Basic Rules</button>
169	      <button class="tab-btn locked" id="leftTab2Btn" onclick="switchLeftTab(2)">2 · Reference Player</button>
170	    </div>
171	
172	    <div class="tab-panel active" id="leftTab1">
173	      <div class="rule-item" data-rule="hands" onclick="toggleRule(this, event)">
174	        <div class="rule-video">
175	          <video src="https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4" muted loop playsinline preload="metadata"></video>
176	          <span class="clip-badge">placeholder clip</span>
177	        </div>
178	        <div class="rule-check-row">
179	          <input type="checkbox">
180	          <span><span class="rule-title">Hand placement</span>Soft, rounded arms — fingers relaxed, wrists gently curved, hands framing the body without tension.</span>
181	        </div>
182	      </div>
183	      <div class="rule-item" data-rule="posture" onclick="toggleRule(this, event)">
184	        <div class="rule-video">
185	          <video src="https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4" muted loop playsinline preload="metadata"></video>
186	          <span class="clip-badge">placeholder clip</span>
187	        </div>
188	        <div class="rule-check-row">
189	          <input type="checkbox">
190	          <span><span class="rule-title">Basic posture</span>Tall spine, engaged core, shoulders relaxed and level, chin lifted — the foundation for every position.</span>
191	        </div>
192	      </div>
193	      <div class="rule-item" data-rule="toes" onclick="toggleRule(this, event)">
194	        <div class="rule-video">
195	          <video src="https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4" muted loop playsinline preload="metadata"></video>
196	          <span class="clip-badge">placeholder clip</span>
197	        </div>
198	        <div class="rule-check-row">
199	          <input type="checkbox">
200	          <span><span class="rule-title">Pointing toes</span>Fully articulate through the foot — ankle, arch, and toes extending in one continuous line.</span>
201	        </div>
202	      </div>
203	      <div class="progress-note" id="ruleProgress">0 / 3 rules confirmed — complete all to unlock the Reference Player.</div>
204	    </div>
205	
206	    <div class="tab-panel" id="leftTab2">
207	      <div class="video-frame" id="refFrame">
208	        <video id="refVideo" playsinline muted></video>
209	        <div class="overlay-badge">Reference · placeholder clip</div>
210	      </div>
211	      <input type="range" class="scrub" id="refScrub" min="0" max="100" value="0">
212	      <div class="controls-row">
213	        <button class="secondary" onclick="toggleRefPlay()" id="refPlayBtn">▶ Play</button>
214	        <button class="secondary" onclick="resetRef()">⟲ Reset</button>
215	      </div>
216	      <div class="status-line" id="refStatus">No sequence generated yet.</div>
217	    </div>
218	  </div>
219	
220	  <!-- RIGHT PANEL -->
221	  <div class="column" id="rightPanel">
222	    <div class="tabs">
223	      <button class="tab-btn active">1 · Capture & Analysis</button>
224	    </div>
225	
226	    <div class="tab-panel active">
227	      <div class="video-frame" id="camFrame">
228	        <video id="camVideo" playsinline muted></video>
229	        <canvas id="camCanvas"></canvas>
230	        <button class="record-trigger" id="recordTrigger" onclick="startStandby()" title="Start standby">●</button>
231	        <div class="countdown-overlay" id="countdownOverlay">3</div>
232	      </div>
233	
234	      <button class="primary" id="generateBtn" onclick="generateSequence()">Generate Sequence</button>
235	
236	      <div class="status-line" id="camStatus">Camera idle. Click Generate Sequence, then the ● trigger to begin.</div>
237	
238	      <div class="score-readout" id="scoreReadout">— %</div>
239	    </div>
240	  </div>
241	</div>
242	
243	<div class="calendar-section">
244	  <h2>Practice Calendar</h2>
245	  <div class="cal-nav">
246	    <button onclick="navMonth(-1)">‹</button>
247	    <div class="cal-month-label" id="calMonthLabel"></div>
248	    <button onclick="navMonth(1)">›</button>
249	  </div>
250	  <div class="cal-weekdays">
251	    <div>Sun</div><div>Mon</div><div>Tue</div><div>Wed</div><div>Thu</div><div>Fri</div><div>Sat</div>
252	  </div>
253	  <div class="cal-grid" id="calGrid"></div>
254	  <div class="footnote">Score ≥ 75% → repeat exercise daily for 3 days (green). Score &lt; 75% → repeat daily for 7 days (red). Use ‹ › to browse any month.</div>
255	</div>
256	
257	<script type="module">
258	import { PoseLandmarker, FilesetResolver } from "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.14/vision_bundle.mjs";
259	
260	/* ---------- CONFIG / PLACEHOLDER ASSETS ---------- */
261	// No real ballet footage was supplied, so a public-domain placeholder clip stands
262	// in for "stitched sequence" clips. Swap PLACEHOLDER_CLIPS with real 9:16 ballet
263	// clips (each representing one figure) when they are available.
264	const PLACEHOLDER_CLIPS = [
265	  "https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4"
266	];
267	const SCORE_THRESHOLD = 75;
268	
269	/* ---------- STATE ---------- */
270	let rulesChecked = new Set();
271	let poseLandmarker = null;
272	let camStream = null;
273	let standbyActive = false;
274	let handRaisedFrames = 0;
275	let recordingActive = false;
276	let liveLandmarksBuffer = [];
277	let lastVideoTime = -1;
278	
279	/* ---------- LEFT TAB: RULES ---------- */
280	window.toggleRule = function(el){
281	  const key = el.dataset.rule;
282	  const cb = el.querySelector("input");
283	  if(rulesChecked.has(key)){
284	    rulesChecked.delete(key);
285	    cb.checked = false;
286	    el.classList.remove("checked");
287	  } else {
288	    rulesChecked.add(key);
289	    cb.checked = true;
290	    el.classList.add("checked");
291	  }
292	  document.getElementById("ruleProgress").textContent =
293	    `${rulesChecked.size} / 3 rules confirmed` +
294	    (rulesChecked.size < 3 ? " — complete all to unlock the Reference Player." : " — Reference Player unlocked!");
295	  if(rulesChecked.size === 3){
296	    document.getElementById("leftTab2Btn").classList.remove("locked");
297	  } else {
298	    document.getElementById("leftTab2Btn").classList.add("locked");
299	    if(document.getElementById("leftTab2").classList.contains("active")) switchLeftTab(1);
300	  }
301	};
302	
303	window.switchLeftTab = function(n){
304	  if(n === 2 && rulesChecked.size < 5) return;
305	  document.getElementById("leftTab1").classList.toggle("active", n===1);
306	  document.getElementById("leftTab2").classList.toggle("active", n===2);
307	  document.getElementById("leftTab1Btn").classList.toggle("active", n===1);
308	  document.getElementById("leftTab2Btn").classList.toggle("active", n===2);
309	};
310	
311	/* ---------- LEFT TAB: REFERENCE PLAYER ---------- */
312	const refVideo = document.getElementById("refVideo");
313	const refScrub = document.getElementById("refScrub");
314	
315	refVideo.addEventListener("timeupdate", () => {
316	  if(refVideo.duration) refScrub.value = (refVideo.currentTime / refVideo.duration) * 100;
317	});
318	refScrub.addEventListener("input", () => {
319	  if(refVideo.duration) refVideo.currentTime = (refScrub.value/100) * refVideo.duration;
320	});
321	
322	window.toggleRefPlay = function(){
323	  if(refVideo.paused){ refVideo.play(); document.getElementById("refPlayBtn").textContent = "⏸ Pause"; }
324	  else { refVideo.pause(); document.getElementById("refPlayBtn").textContent = "▶ Play"; }
325	};
326	window.resetRef = function(){
327	  refVideo.pause();
328	  refVideo.currentTime = 0;
329	  document.getElementById("refPlayBtn").textContent = "▶ Play";
330	};
331	
332	window.generateSequence = function(){
333	  // Stitches PLACEHOLDER_CLIPS end-to-end into the reference player (simple
334	  // sequential-src approach — a real backend would concat/transcode into one file).
335	  let idx = 0;
336	  refVideo.src = PLACEHOLDER_CLIPS[idx];
337	  refVideo.onended = () => {
338	    idx++;
339	    if(idx < PLACEHOLDER_CLIPS.length){ refVideo.src = PLACEHOLDER_CLIPS[idx]; refVideo.play(); }
340	  };
341	  document.getElementById("refStatus").textContent =
342	    `Sequence generated (${PLACEHOLDER_CLIPS.length} clip stitched). Projected into Left Panel player.`;
343	  document.getElementById("camStatus").textContent = "Sequence ready. Click the ● trigger to start standby.";
344	};
345	
346	/* ---------- RIGHT PANEL: CAMERA + POSE ---------- */
347	const camVideo = document.getElementById("camVideo");
348	const camCanvas = document.getElementById("camCanvas");
349	const ctx = camCanvas.getContext("2d");
350	const camFrame = document.getElementById("camFrame");
351	const countdownOverlay = document.getElementById("countdownOverlay");
352	
353	async function initPose(){
354	  const filesetResolver = await FilesetResolver.forVisionTasks(
355	    "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.14/wasm"
356	  );
357	  poseLandmarker = await PoseLandmarker.createFromOptions(filesetResolver, {
358	    baseOptions: {
359	      modelAssetPath: "https://storage.googleapis.com/mediapipe-models/pose_landmarker/pose_landmarker_lite/float16/1/pose_landmarker_lite.task",
360	      delegate: "GPU"
361	    },
362	    runningMode: "VIDEO",
363	    numPoses: 1
364	  });
365	}
366	
367	async function initCamera(){
368	  try{
369	    camStream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: "user" } });
370	    camVideo.srcObject = camStream;
371	    await camVideo.play();
372	    camCanvas.width = camVideo.videoWidth || 360;
373	    camCanvas.height = camVideo.videoHeight || 640;
374	    document.getElementById("camStatus").textContent = "Camera live. Stand back and raise a hand to trigger the countdown.";
375	    predictLoop();
376	  }catch(err){
377	    document.getElementById("camStatus").textContent =
378	      "Camera access denied or unavailable: " + err.message;
379	  }
380	}
381	
382	function predictLoop(){
383	  if(!poseLandmarker || camVideo.readyState < 2){ requestAnimationFrame(predictLoop); return; }
384	  if(camVideo.currentTime !== lastVideoTime){
385	    lastVideoTime = camVideo.currentTime;
386	    const result = poseLandmarker.detectForVideo(camVideo, performance.now());
387	    drawLandmarks(result);
388	    handleGesture(result);
389	    if(recordingActive) liveLandmarksBuffer.push(result.landmarks?.[0] || null);
390	  }
391	  requestAnimationFrame(predictLoop);
392	}
393	
394	function drawLandmarks(result){
395	  ctx.clearRect(0,0,camCanvas.width,camCanvas.height);
396	  const lm = result.landmarks?.[0];
397	  if(!lm) return;
398	  ctx.fillStyle = "#c9a0dc";
399	  lm.forEach(pt => {
400	    ctx.beginPath();
401	    ctx.arc(pt.x*camCanvas.width, pt.y*camCanvas.height, 3, 0, Math.PI*2);
402	    ctx.fill();
403	  });
404	}
405	
406	// 33-point MediaPipe indices: 15 = left wrist, 16 = right wrist, 11/12 = shoulders
407	function handleGesture(result){
408	  if(!standbyActive || recordingActive) return;
409	  const lm = result.landmarks?.[0];
410	  if(!lm) { handRaisedFrames = 0; return; }
411	  const leftWristUp = lm[15].y < lm[11].y;
412	  const rightWristUp = lm[16].y < lm[12].y;
413	  if(leftWristUp || rightWristUp){
414	    handRaisedFrames++;
415	    if(handRaisedFrames > 8){ // ~sustained raise, avoid false positives
416	      standbyActive = false;
417	      handRaisedFrames = 0;
418	      beginCountdown();
419	    }
420	  } else {
421	    handRaisedFrames = 0;
422	  }
423	}
424	
425	window.startStandby = function(){
426	  if(!camStream){ document.getElementById("camStatus").textContent = "Camera not ready yet."; return; }
427	  standbyActive = true;
428	  document.getElementById("camStatus").textContent =
429	    "Standby: step back into frame and raise a hand to trigger the countdown.";
430	};
431	
432	function beginCountdown(){
433	  document.getElementById("camStatus").textContent = "Hand detected — get ready.";
434	  let n = 3;
435	  countdownOverlay.textContent = n;
436	  countdownOverlay.classList.add("show");
437	  const interval = setInterval(() => {
438	    n--;
439	    if(n > 0){
440	      countdownOverlay.textContent = n;
441	    } else {
442	      countdownOverlay.textContent = "Dance!";
443	      clearInterval(interval);
444	      setTimeout(() => {
445	        countdownOverlay.classList.remove("show");
446	        launchSyncedTake();
447	      }, 700);
448	    }
449	  }, 1000);
450	}
451	
452	function launchSyncedTake(){
453	  // Frame-perfect sync: reset + autoplay reference video exactly as recording begins.
454	  refVideo.currentTime = 0;
455	  refVideo.play();
456	  document.getElementById("refPlayBtn").textContent = "⏸ Pause";
457	  recordingActive = true;
458	  liveLandmarksBuffer = [];
459	  document.getElementById("camStatus").textContent = "Recording — mirror the reference sequence now.";
460	  refVideo.onended = () => finishTake();
461	}
462	
463	function finishTake(){
464	  recordingActive = false;
465	  document.getElementById("camStatus").textContent = "Session ended. Scoring movement similarity…";
466	  const score = computeMatchScore(liveLandmarksBuffer);
467	  applyScore(score);
468	}
469	
470	/* ---------- SCORING ----------
471	   Placeholder heuristic: real implementation should compare joint angles
472	   (shoulder-hip-knee, hip-knee-ankle, etc.) frame-by-frame against
473	   pre-computed reference landmark data for the stitched clip. Since no
474	   reference landmark dataset was supplied, this scores based on how
475	   consistently a full-body pose (all 33 landmarks with reasonable
476	   visibility) was tracked throughout the take, as a stand-in signal for
477	   "clean, trackable technique." Swap computeMatchScore() for real
478	   angle-comparison against reference data once available. */
479	function computeMatchScore(buffer){
480	  const validFrames = buffer.filter(f => f && f.length === 33);
481	  if(buffer.length === 0) return 0;
482	  const coverage = validFrames.length / buffer.length;
