file.content:
.video-frame{
  position:relative; width:100%; aspect-ratio:9/16; background:#000; border-radius:12px; overflow:hidden;
  border:4px solid #2a2434; transition:border-color .3s ease, box-shadow .3s ease;
}
.video-frame video, .video-frame canvas{
  width:100%; height:100%; object-fit:cover; position:absolute; top:0; left:0;
}
.video-frame.border-green{border-color:var(--green); box-shadow:0 0 22px 2px rgba(61,220,132,.55);}
.video-frame.border-red{border-color:var(--red); box-shadow:0 0 22px 2px rgba(255,77,94,.55);}

/* Invert (mirror) the camera sensor feed so it behaves like a mirror,
   matching what the person sees of themselves. Video + canvas overlay
   are flipped together so pose landmarks stay aligned. */
#camVideo, #camCanvas{
  transform: scaleX(-1);
}

.overlay-badge{
  position:absolute; top:8px; left:8px; background:rgba(0,0,0,.55); padding:4px 9px; border-radius:6px;
  font-size:.68rem; letter-spacing:.4px; z-index:5;
}
.record-trigger{
  position:absolute; top:8px; left:8px; z-index:6; background:rgba(255,77,94,.9); border:none; color:#fff;
  width:34px; height:34px; border-radius:50%; cursor:pointer; font-size:.9rem; display:flex; align-items:center; justify-content:center;
}
.countdown-overlay{
  position:absolute; inset:0; display:none; align-items:center; justify-content:center; z-index:20;
  background:rgba(0,0,0,.45); font-size:4rem; font-weight:700; color:var(--accent2);
}
.countdown-overlay.show{display:flex;}

.controls-row{display:flex; gap:8px;}
button.primary{
  background:linear-gradient(135deg,var(--accent),#8f6bb0); border:none; color:#1a1420; font-weight:700;
  padding:11px; border-radius:9px; cursor:pointer; font-size:.82rem; flex:1;
}
button.primary:disabled{opacity:.4; cursor:not-allowed;}
button.secondary{
  background:var(--panel2); border:1px solid #332b40; color:var(--text); padding:11px; border-radius:9px;

