/* ---------- RIGHT PANEL: SEQUENCE BUILDER (focus + exercise count) ---------- */
const FOCUS_HINTS = {
  turnout: "Turnout: tendu, coupé, passé",
  technique: "Technique: plié, rond de jambe, rond de jambe en dedans"
};

window.setFocus = function(focus){
  currentFocus = focus;
  document.getElementById("focusTurnoutBtn").classList.toggle("active", focus === "turnout");
  document.getElementById("focusTechniqueBtn").classList.toggle("active", focus === "technique");
  const max = CLIP_POOLS[focus].length;
  const countInput = document.getElementById("exerciseCount");
  countInput.max = max;
  if(Number(countInput.value) > max || !countInput.value) countInput.value = Math.min(5, max);
  document.getElementById("seqBuilderHint").textContent = `${FOCUS_HINTS[focus]} — up to ${max} available.`;
};

/* ---------- LEFT TAB: REFERENCE PLAYER (continuous stitched timeline) ---------- */
const refVideo = document.getElementById("refVideo");
const refScrub = document.getElementById("refScrub");
const refBadge = document.getElementById("refBadge");
const seqTimeLabel = document.getElementById("seqTimeLabel");

function formatTime(sec){
  sec = Math.max(0, Math.floor(sec || 0));
  const m = Math.floor(sec / 60), s = sec % 60;
  return `${m}:${String(s).padStart(2, "0")}`;
}

// Reads a clip's duration without disturbing the visible player, so the
// combined timeline can be computed before playback starts.
function getVideoDuration(src){
  return new Promise((resolve) => {
    const probe = document.createElement("video");
    probe.preload = "metadata";
    probe.muted = true;
    probe.src = src;
    probe.addEventListener("loadedmetadata", () => resolve(probe.duration || 0), { once:true });
    probe.addEventListener("error", () => resolve(0), { once:true });
  });
}

// Loads/plays a specific clip in the sequence at a given local (within-clip)
// time. Skips the reload if that clip is already the one loaded.
function playClipAt(index, localTime, autoplay){
  seqIndex = index;
  const clip = seqClips[index];
  refVideo.classList.toggle("fit-contain", /pliefront\.mp4$/.test(clip.src));
  refBadge.textContent = `Reference · ${clip.label} (${index + 1}/${seqClips.length})`;
  const seekAndGo = () => {
    try { refVideo.currentTime = localTime || 0; } catch(e){}
    if(autoplay) refVideo.play(); else refVideo.pause();
  };
  if(loadedClipIndex === index){
    seekAndGo();
  } else {
    loadedClipIndex = index;
    refVideo.src = clip.src;
    refVideo.addEventListener("loadedmetadata", seekAndGo, { once:true });
  }
}

refVideo.addEventListener("timeupdate", () => {
  if(!seqClips.length) return;
  const globalElapsed = (seqCumStart[seqIndex] || 0) + (refVideo.currentTime || 0);
  if(seqTotalDuration > 0) refScrub.value = (globalElapsed / seqTotalDuration) * 100;
  seqTimeLabel.textContent = `${formatTime(globalElapsed)} / ${formatTime(seqTotalDuration)}`;
});

refVideo.addEventListener("ended", () => {
  if(!seqClips.length) return;
  if(seqIndex + 1 < seqClips.length){
    playClipAt(seqIndex + 1, 0, true);
  } else {
    document.getElementById("refStatus").textContent = "Sequence complete — press ⟲ Reset or Generate a new one.";
    document.getElementById("refPlayBtn").textContent = "▶ Play";
  }
});

refScrub.addEventListener("input", () => {
  if(!seqTotalDuration || !seqClips.length) return;
  const targetGlobal = (refScrub.value / 100) * seqTotalDuration;
  let idx = seqClips.length - 1;
  for(let i = 0; i < seqCumStart.length; i++){
    const start = seqCumStart[i];
    const end = start + (seqDurations[i] || 0);
    if(targetGlobal >= start && targetGlobal < end){ idx = i; break; }
  }
  const localTime = Math.max(0, targetGlobal - seqCumStart[idx]);
  const wasPlaying = !refVideo.paused;
  playClipAt(idx, localTime, wasPlaying);
});

window.toggleRefPlay = function(){
  if(refVideo.paused){ refVideo.play(); document.getElementById("refPlayBtn").textContent = "⏸ Pause"; }
  else { refVideo.pause(); document.getElementById("refPlayBtn").textContent = "▶ Play"; }
};
window.resetRef = function(){
  refVideo.pause();
  document.getElementById("refPlayBtn").textContent = "▶ Play";
  if(seqClips.length) playClipAt(0, 0, false);
};

window.generateSequence = async function(){
  if(rulesChecked.size < 3){
    document.getElementById("camStatus").textContent =
      "Complete all 3 Basic Rules (left panel) before generating a sequence.";
    return;
  }
  const pool = CLIP_POOLS[currentFocus];
  let count = parseInt(document.getElementById("exerciseCount").value, 10);
  if(isNaN(count) || count < 1) count = 1;
  if(count > pool.length) count = pool.length;
  document.getElementById("exerciseCount").value = count;

  const clips = pool.slice(0, count);
  document.getElementById("refStatus").textContent = "Loading sequence…";
  document.getElementById("camStatus").textContent = "Preparing your custom sequence…";

  // Preload every clip's duration up front so scrubbing/timeupdate can be
  // mapped against the FULL stitched-sequence timeline, not just whichever
  // individual clip happens to be loaded at that moment.
  const durations = await Promise.all(clips.map(c => getVideoDuration(c.src)));

  seqClips = clips;
  seqDurations = durations;
  seqCumStart = [];
  let acc = 0;
  durations.forEach(d => { seqCumStart.push(acc); acc += d; });
  seqTotalDuration = acc;
  loadedClipIndex = -1;

  sequenceGenerated = true;
  updateAccessState();
  playClipAt(0, 0, true);

  document.getElementById("refStatus").textContent =
    `Sequence generated — ${clips.length} ${currentFocus} exercises, ${formatTime(seqTotalDuration)} total. Reference Player unlocked.`;
  document.getElementById("camStatus").textContent = "Sequence ready. Click the ● trigger to start standby.";
  switchLeftTab(2); // now unlocked — jump straight to it
};

