      countdownOverlay.textContent = "Dance!";
      clearInterval(interval);
      setTimeout(() => {
        countdownOverlay.classList.remove("show");
        launchSyncedTake();
      }, 700);
    }
  }, 1000);
}

function launchSyncedTake(){
  // Frame-perfect sync: reset + autoplay reference video exactly as recording begins.
  refVideo.currentTime = 0;
  refVideo.play();
  document.getElementById("refPlayBtn").textContent = "⏸ Pause";
  recordingActive = true;
  liveLandmarksBuffer = [];
  document.getElementById("camStatus").textContent = "Recording — mirror the reference sequence now.";
  refVideo.onended = () => finishTake();
}

function finishTake(){
  recordingActive = false;
  document.getElementById("camStatus").textContent = "Session ended. Scoring movement similarity…";
  const score = computeMatchScore(liveLandmarksBuffer);
  applyScore(score);
}

/* ---------- SCORING ----------
   Placeholder heuristic: real implementation should compare joint angles
   (shoulder-hip-knee, hip-knee-ankle, etc.) frame-by-frame against
   pre-computed reference landmark data for the stitched clip. Since no
   reference landmark dataset was supplied, this scores based on how
   consistently a full-body pose (all 33 landmarks with reasonable
   visibility) was tracked throughout the take, as a stand-in signal for
   "clean, trackable technique." Swap computeMatchScore() for real
   angle-comparison against reference data once available. */
function computeMatchScore(buffer){
  const validFrames = buffer.filter(f => f && f.length === 33);
  if(buffer.length === 0) return 0;
  const coverage = validFrames.length / buffer.length;
  const avgVisibility = validFrames.length
    ? validFrames.reduce((sum, f) => sum + f.reduce((s,p)=>s+(p.visibility||0),0)/f.length, 0) / validFrames.length
    : 0;
  const score = Math.round(Math.min(100, coverage * avgVisibility * 100));
  return score;
}

function applyScore(score){
  const readout = document.getElementById("scoreReadout");
  readout.textContent = score + "%";
  const pass = score >= SCORE_THRESHOLD;
  readout.className = "score-readout " + (pass ? "green" : "red");
  camFrame.classList.remove("border-green","border-red");
  camFrame.classList.add(pass ? "border-green" : "border-red");
  document.getElementById("camStatus").textContent =
    `Final score: ${score}%. ${pass ? "Mastery — green border." : "Needs review — red border."}`;
  scheduleTasksFromToday(pass ? 3 : 7, pass);
}

