function dateKey(d){
  return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
}

// Marks the next N calendar days (starting tomorrow) with a pass/fail task,
// so results are visible regardless of which month the user is browsing.
function scheduleTasksFromToday(days, pass){
  for(let i=1;i<=days;i++){
    const d = new Date(todayReal);
    d.setDate(todayReal.getDate()+i);
    practiceTasks[dateKey(d)] = pass ? "green" : "red";
  }
  renderCalendar();
}

window.navMonth = function(delta){
  viewMonth += delta;
  if(viewMonth < 0){ viewMonth = 11; viewYear--; }
  if(viewMonth > 11){ viewMonth = 0; viewYear++; }
  renderCalendar();
};

