const MONTH_NAMES = ["January","February","March","April","May","June","July","August","September","October","November","December"];

function renderCalendar(){
  const grid = document.getElementById("calGrid");
  grid.innerHTML = "";
  document.getElementById("calMonthLabel").textContent = `${MONTH_NAMES[viewMonth]} ${viewYear}`;

  const firstOfMonth = new Date(viewYear, viewMonth, 1);
  const startOffset = firstOfMonth.getDay(); // 0 = Sunday
  const daysInMonth = new Date(viewYear, viewMonth+1, 0).getDate();

  for(let i=0;i<startOffset;i++){
    const empty = document.createElement("div");
    empty.className = "cal-cell empty";
    grid.appendChild(empty);
  }

  for(let day=1; day<=daysInMonth; day++){
    const d = new Date(viewYear, viewMonth, day);
    const key = dateKey(d);
    const cell = document.createElement("div");
    cell.className = "cal-cell";
    const isToday = d.toDateString() === todayReal.toDateString();
    if(isToday) cell.classList.add("today");
    const task = practiceTasks[key];
    if(task) cell.classList.add(task === "green" ? "task-green" : "task-red");
    cell.innerHTML = `<div class="dnum">${day}</div>` + (task ? `<div style="font-size:.62rem;">practice</div>` : "");
    grid.appendChild(cell);
  }
}
renderCalendar();

/* ---------- BOOT ---------- */
setFocus("turnout"); // initializes the exercise-count max + hint text
initPose();
initCamera();

