function applyScore(score){
  const readout = document.getElementById("scoreReadout");
  readout.textContent = score + "%";
  const pass = score >= SCORE_THRESHOLD;
  readout.className = "score-readout " + (pass ? "green" : "red");
  camFrame.classList.remove("border-green","border-red");
  camFrame.classList.add(pass ? "border-green" : "border-red");

  const todayKey = dateKey(todayReal);
  if(pass && seqClips.length){
    // Only the exercises actually attempted in this take get checked off,
    // and only because the score cleared the 75% bar.
    if(!dailyChecklist[todayKey]) dailyChecklist[todayKey] = new Set();
    seqClips.forEach(c => dailyChecklist[todayKey].add(exerciseKeyFromSrc(c.src)));
    checkStreakProgress(todayKey);
    document.getElementById("camStatus").textContent =
      `Final score: ${score}%. Mastery — ${seqClips.length} exercise(s) checked off today.`;
  } else if(pass){
    document.getElementById("camStatus").textContent = `Final score: ${score}%. Mastery — but no sequence was attempted, so nothing to check off.`;
  } else {
    document.getElementById("camStatus").textContent =
      `Final score: ${score}%. Below 75% — today's attempted exercises were NOT checked off. Try again.`;
  }
  renderCalendar();
  renderDailyChecklist(selectedDayKey || todayKey);
}

/* ---------- PRACTICE CALENDAR + DAILY EXERCISE CHECKLIST ---------- */
// All 14 trackable exercises (both focus pools combined), keyed by filename.
function exerciseKeyFromSrc(src){
  return src.split("/").pop().replace(/\.mp4$/, "");
}
const ALL_EXERCISES = [...CLIP_POOLS.turnout, ...CLIP_POOLS.technique].map(c => ({
  key: exerciseKeyFromSrc(c.src),
  label: c.label
}));

const todayReal = new Date();
let viewYear = todayReal.getFullYear();
let viewMonth = todayReal.getMonth(); // 0-indexed
let selectedDayKey = null;

const dailyChecklist = {};               // "YYYY-MM-DD" -> Set of exercise keys completed that day
const streakRegisteredDays = new Set();  // days already counted toward the streak (avoids double-counting)
let streakCount = 0;
let lastFullCompletionAt = null;         // Date a day's checklist last hit 14/14

function dateKey(d){
  return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
}

// Fires whenever today's checklist changes; registers a streak completion
// the first (and only the first) time that day reaches all 14 exercises.
function checkStreakProgress(key){
  const set = dailyChecklist[key];
  if(!set || set.size < ALL_EXERCISES.length) return;
  if(streakRegisteredDays.has(key)) return;
  streakRegisteredDays.add(key);
  registerFullCompletion(new Date());
}

function registerFullCompletion(now){
  if(lastFullCompletionAt){
    const hoursSince = (now - lastFullCompletionAt) / 3600000;
    streakCount = hoursSince <= 30 ? streakCount + 1 : 1; // >30h gap breaks the streak
  } else {
    streakCount = 1;
  }
  lastFullCompletionAt = now;
  updateStreakDisplay();
}

// The streak reads as 0 once more than 30 hours have passed since the last
// full-checklist day — computed on demand, no background timer required.
function getEffectiveStreak(){
  if(!lastFullCompletionAt) return 0;
  const hoursSince = (Date.now() - lastFullCompletionAt) / 3600000;
  return hoursSince > 30 ? 0 : streakCount;
}

function updateStreakDisplay(){
  const banner = document.getElementById("streakBanner");
  const effective = getEffectiveStreak();
  if(effective === 0){
    banner.textContent = "🔥 Streak: 0 days — complete all 14 exercises in one day to start your streak.";
    banner.classList.remove("streak-warning");
    return;
  }
  const hoursSince = (Date.now() - lastFullCompletionAt) / 3600000;
  const warn = hoursSince >= 25;
  let text = `🔥 Streak: ${effective} day${effective === 1 ? "" : "s"}`;
  if(warn) text += ` ⏳ resets in ~${Math.max(0, Math.ceil(30 - hoursSince))}h — complete today's 14 to keep it going!`;
  banner.textContent = text;
  banner.classList.toggle("streak-warning", warn);
}

window.navMonth = function(delta){
  viewMonth += delta;
  if(viewMonth < 0){ viewMonth = 11; viewYear--; }
  if(viewMonth > 11){ viewMonth = 0; viewYear++; }
  renderCalendar();
};

window.selectCalDay = function(key){
  renderDailyChecklist(key);
  renderCalendar();
};

const MONTH_NAMES = ["January","February","March","April","May","June","July","August","September","October","November","December"];

function renderCalendar(){
  const grid = document.getElementById("calGrid");
  grid.innerHTML = "";
  document.getElementById("calMonthLabel").textContent = `${MONTH_NAMES[viewMonth]} ${viewYear}`;

  const firstOfMonth = new Date(viewYear, viewMonth, 1);
  const startOffset = firstOfMonth.getDay(); // 0 = Sunday
  const daysInMonth = new Date(viewYear, viewMonth+1, 0).getDate();
  const todayKey = dateKey(todayReal);
  const hoursSinceCompletion = lastFullCompletionAt ? (Date.now() - lastFullCompletionAt) / 3600000 : Infinity;
  const showHourglass = hoursSinceCompletion >= 25 && hoursSinceCompletion <= 30;

  for(let i=0;i<startOffset;i++){
    const empty = document.createElement("div");
    empty.className = "cal-cell empty";
    grid.appendChild(empty);
  }

  for(let day=1; day<=daysInMonth; day++){
    const d = new Date(viewYear, viewMonth, day);
    const key = dateKey(d);
    const cell = document.createElement("div");
    cell.className = "cal-cell";
    cell.onclick = () => selectCalDay(key);
    if(key === todayKey) cell.classList.add("today");
    if(key === selectedDayKey) cell.classList.add("selected");

    const done = dailyChecklist[key] ? dailyChecklist[key].size : 0;
    const total = ALL_EXERCISES.length;
    if(done === total) cell.classList.add("task-green");
    else if(done > 0) cell.classList.add("task-partial");

    let extra = done > 0 ? `<div style="font-size:.6rem;">${done}/${total}</div>` : "";
    if(key === todayKey && showHourglass) extra += `<div style="font-size:.75rem;">⏳</div>`;
    cell.innerHTML = `<div class="dnum">${day}</div>` + extra;
    grid.appendChild(cell);
  }
  updateStreakDisplay();
}

function formatDateLabel(key){
  const [y,m,d] = key.split("-").map(Number);
  return `${MONTH_NAMES[m-1]} ${d}, ${y}`;
}

function renderDailyChecklist(key){
  selectedDayKey = key;
  const isToday = key === dateKey(todayReal);
  const set = dailyChecklist[key] || new Set();
  document.getElementById("dailyChecklistDateLabel").textContent = isToday ? "Today" : formatDateLabel(key);
  document.getElementById("dailyChecklistCount").textContent = `${set.size} / ${ALL_EXERCISES.length}`;
  const wrap = document.getElementById("dailyChecklistGrid");
  wrap.innerHTML = "";
  ALL_EXERCISES.forEach(ex => {
    const done = set.has(ex.key);
    const item = document.createElement("div");
    item.className = "daily-ex-item" + (done ? " checked" : "");
    item.innerHTML = `<input type="checkbox" ${done ? "checked" : ""} disabled><span>${ex.label}</span>`;
    wrap.appendChild(item);
  });
}

renderDailyChecklist(dateKey(todayReal));
renderCalendar();

/* ---------- BOOT ---------- */
setFocus("turnout"); // initializes the exercise-count max + hint text
initPose();
initCamera();

// Keep the streak banner / hourglass warning live as time passes, without
// requiring any user interaction.
setInterval(() => { updateStreakDisplay(); renderCalendar(); }, 60000);

