const FOCUS_BTN_IDS = { turnout: "focusTurnoutBtn", technique: "focusTechniqueBtn", both: "focusBothBtn" };

window.setFocus = function(focus){
  currentFocus = focus;
  Object.keys(FOCUS_BTN_IDS).forEach(f => {
    document.getElementById(FOCUS_BTN_IDS[f]).classList.toggle("active", f === focus);
  });
  const max = CLIP_POOLS[focus].length;
  const countInput = document.getElementById("exerciseCount");
  countInput.max = max;
  if(Number(countInput.value) > max || !countInput.value) countInput.value = Math.min(5, max);
  document.getElementById("seqBuilderHint").textContent = `${FOCUS_HINTS[focus]} — up to ${max} available.`;
};

